mapper.insert:
merge into SourceInfo a using (select #{sourceInfo.sourceProtocol,jdbcType=VARCHAR} as sourceProtocol, #{sourceInfo.tableName,jdbcType=VARCHAR} as tableName, #{sourceInfo.sourceSystem,jdbcType=VARCHAR} as sourceSystem from dual) b on ( upper(a.SOURCEPROTOCOL) = upper(b.sourceProtocol) and upper(a.TABLENAME) = upper(b.tableName) and upper(a.SOURCESYSTEM) = upper(b.sourceSystem)) when matched then update set id = #{sourceInfo.id}
,UPDATE_TIME = #{sourceInfo.updateTime}
,SOURCEFIRM = #{sourceInfo.sourceFirm,jdbcType=VARCHAR}
when not matched then insert values (#{sourceInfo.id},#{sourceInfo.createTime},#{sourceInfo.updateTime}, #{sourceInfo.sourceProtocol,jdbcType=VARCHAR},#{sourceInfo.tableName,jdbcType=VARCHAR}, #{sourceInfo.sourceSystem,jdbcType=VARCHAR},#{sourceInfo.sourceFirm,jdbcType=VARCHAR},null,null,null,null,null)
